func routeLiterals(content string) []string {
	re := regexp.MustCompile(`["'](/[A-Za-z0-9_\-/{}/:.]*)["']`)
	seen := map[string]struct{}{}
	for _, match := range re.FindAllStringSubmatch(content, -1) {
